"}\n"
"\n"
"/* Header Styles */\n"
"QHeaderView::section {\n"
"    background-color: #4682b4; /* Medium blue background for headers */\n"
"    color: #ffffff; /* White text for contrast */\n"
"    font-size: 18px; /* Larger font size for better visibility */\n"
"    font-weight: bold; /* Bold text for emphasis */\n"
"    border: 1px solid #1a3c6e; /* Dark blue border for sections */\n"
"    padding: 8px; /* Increased padding for more space */\n"
"    text-align: center; /* Center-align text in headers */\n"
"    height: 30px; /* Increase header height for better readability */\n"
"}\n"
"\n"
"/* Fix for Horizontal Header Stretch */\n"
"QHeaderView::section:horizontal {\n"
"    min-width: 100px; /* Minimum width for each column header */\n"
"}\n"
"\n"
"/* Fix for Vertical Header (Index Column) */\n"
"QHeaderView::section:vertical {\n"
"    background-color: #f0faff; /* Light blue for index column */\n"
"    font-weight: bold; /* Bold text for better visibility */\n"
"    font-size: 16px; /* Match the cell font size */\n"
