"/* Selected Cell Styling */\n"
"QTableWidget::item:selected {\n"
"    background-color: #5a9bd6; /* Lighter blue for selected cell */\n"
"    color: #ffffff; /* White text for better contrast */\n"
"}\n"
"\n"
"/* Scrollbar Styling */\n"
